import jsonStringify from"fastest-stable-stringify";import*as Schema from"../schema.js";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/enum",compile=e=>Schema.value(e).map(jsonStringify),interpret=(e,t)=>e.some(e=>jsonStringify(Instance.value(t))===e);export default{id:id,compile:compile,interpret:interpret};